def n_queens_count(n):
    def backtrack(row, cols, diag1, diag2):
        if row == n:
            return 1
        count = 0
        for col in range(n):
            d1 = row - col + n - 1
            d2 = row + col
            if not (cols & (1 << col) or diag1 & (1 << d1) or diag2 & (1 << d2)):
                count += backtrack(row + 1,
                                   cols | (1 << col),
                                   diag1 | (1 << d1),
                                   diag2 | (1 << d2))
        return count
    return backtrack(0, 0, 0, 0)
